export const JUGGERNAUT_RAIL_ICON_ASSET_URLS = JUGGERNAUT_RAIL_ICON_PACK_ASSET_URLS[DEFAULT_JUGGERNAUT_RAIL_ICON_PACK_ID];

export function getJuggernautRailIconAssetUrl(toolId = "", packId = DEFAULT_JUGGERNAUT_RAIL_ICON_PACK_ID) {
  const normalizedToolId = String(toolId || "").trim();
  const normalizedPackId = normalizePackId(packId);
  const pack = JUGGERNAUT_RAIL_ICON_PACK_ASSET_URLS[normalizedPackId] || JUGGERNAUT_RAIL_ICON_PACK_ASSET_URLS[DEFAULT_JUGGERNAUT_RAIL_ICON_PACK_ID] || {};
  return pack[normalizedToolId] || JUGGERNAUT_RAIL_ICON_ASSET_URLS[normalizedToolId] || "";
}

export function getJuggernautRailIconMarkup(toolId = "", packId = DEFAULT_JUGGERNAUT_RAIL_ICON_PACK_ID) {
  const normalizedToolId = String(toolId || "").trim();
  const normalizedPackId = normalizePackId(packId);
  const assetUrl = getJuggernautRailIconAssetUrl(normalizedToolId, normalizedPackId);
  if (!assetUrl) return "";
  const toolClass = `tool-icon-${normalizedToolId.replace(/_/g, "-")}`;
  const packClass = `tool-icon-pack-${normalizedPackId.replace(/_/g, "-")}`;
  return `<span class="tool-icon tool-icon-mask ${toolClass} ${packClass}" aria-hidden="true" style="--tool-icon-mask:url('${escapeCssUrl(assetUrl)}')"></span>`;
}
